## SetAutoPlay - 自动播放开关（与 Unity 版一致）
## 外部调用 toggle() 切换自动转向模式

@export var controller: AutoPlayController

var _active: bool = false

func toggle() -> void:
	_active = !_active
	if not controller:
		return
	controller.set_holder(_active)
	if controller.player:
		controller.player.disallow_input = _active
